import re
import os
import glob

base_dir = '.'

# Map of type names to their Deserialize method names
deserialize_methods = {
    'SystemData': 'SystemData.DeserializeSystemData',
    'ArmPlan': 'ArmPlan.DeserializeArmPlan',
    'ManagedServiceIdentity': 'ManagedServiceIdentity.DeserializeManagedServiceIdentity',
    'ExtendedLocation': 'ExtendedLocation.DeserializeExtendedLocation',
    'SubResource': 'SubResource.DeserializeSubResource',
    'UserAssignedIdentity': 'UserAssignedIdentity.DeserializeUserAssignedIdentity',
    'OperationStatusResult': 'DeserializeOperationStatusResult',  # same class
}

# Types to keep using JsonSerializer (no IJsonModel implementation)
keep_json_serializer = {'ResponseError'}

changes_made = {}

# Find all .cs files (excluding ManagedServiceIdentity.Serialization.cs which was handled manually)
for filepath in glob.glob(os.path.join(base_dir, '**', '*.cs'), recursive=True):
    if 'Common/Custom/Models/ManagedServiceIdentity.Serialization.cs' in filepath:
        continue

    with open(filepath, 'r') as f:
        original = f.read()

    content = original
    file_changes = []

    # Pattern 1: JsonSerializer.Serialize(writer, document.RootElement);
    # Replace with: document.RootElement.WriteTo(writer);
    pattern1 = r'JsonSerializer\.Serialize\(writer, document\.RootElement\);'
    if re.search(pattern1, content):
        content = re.sub(pattern1, 'document.RootElement.WriteTo(writer);', content)
        file_changes.append('document.RootElement.WriteTo(writer)')

    # Pattern 2: JsonSerializer.Serialize(writer, <Variable>);
    # Replace with: writer.WriteObjectValue(<Variable>, options);
    # But NOT for document.RootElement (already handled) and NOT for ResponseError
    # Match: JsonSerializer.Serialize(writer, SomeVar); where SomeVar is a simple identifier
    pattern2 = r'JsonSerializer\.Serialize\(writer, (\w+)\);'
    def replace_serialize(match):
        var_name = match.group(1)
        if var_name == 'document':  # skip document.RootElement (already handled)
            return match.group(0)
        return f'writer.WriteObjectValue({var_name}, options);'

    new_content = re.sub(pattern2, replace_serialize, content)
    if new_content != content:
        file_changes.append('writer.WriteObjectValue')
        content = new_content

    # Pattern 3: JsonSerializer.Deserialize<T>(property.Value.GetRawText())
    # Replace with: T.DeserializeT(property.Value, options) or T.DeserializeT(property.Value)
    pattern3 = r'JsonSerializer\.Deserialize<(\w+)>\((\w+)\.Value\.GetRawText\(\)\)'
    def replace_deserialize_property(match):
        type_name = match.group(1)
        prop_name = match.group(2)
        if type_name in keep_json_serializer:
            return match.group(0)
        if type_name in deserialize_methods:
            method = deserialize_methods[type_name]
            return f'{method}({prop_name}.Value, options)'
        return match.group(0)

    new_content = re.sub(pattern3, replace_deserialize_property, content)
    if new_content != content:
        file_changes.append('DeserializeXxx(property.Value)')
        content = new_content

    # Pattern 4: JsonSerializer.Deserialize<T>(item.GetRawText())
    # For array item enumeration - item is already a JsonElement
    pattern4 = r'JsonSerializer\.Deserialize<(\w+)>\((\w+)\.GetRawText\(\)\)'
    def replace_deserialize_item(match):
        type_name = match.group(1)
        item_name = match.group(2)
        if type_name in keep_json_serializer:
            return match.group(0)
        if type_name in deserialize_methods:
            method = deserialize_methods[type_name]
            return f'{method}({item_name}, options)'
        return match.group(0)

    new_content = re.sub(pattern4, replace_deserialize_item, content)
    if new_content != content:
        file_changes.append('DeserializeXxx(item)')
        content = new_content

    if content != original:
        with open(filepath, 'w') as f:
            f.write(content)
        changes_made[filepath] = file_changes

print(f"Modified {len(changes_made)} files:")
for filepath, changes in sorted(changes_made.items()):
    print(f"  {filepath}: {', '.join(changes)}")
